import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import apiClient from "../../../shared/api/client";

const TEMPLATES = [
  { id: 1, label: "Пустая форма", icon: "+", bg: "#fff", border: "#e5e7eb" },
  { id: 2, label: "Контактная информация", icon: "👤", bg: "#d1fae5", questions: [
    { title: "Ваше имя", type: "text", options: [], required: true },
    { title: "Ваша электронная почта", type: "text", options: [], required: true },
    { title: "Ваш номер телефона", type: "text", options: [], required: true },
    { title: "Название компании", type: "text", options: [], required: false },
  ]},
  { id: 3, label: "Ответ на приглашение", icon: "✓", bg: "#fef9c3", questions: [
    { title: "Ваше имя", type: "text", options: [], required: true },
    { title: "Вы посетите мероприятие?", type: "radio", options: ["Да", "Возможно", "Нет"], required: true },
  ]},
  { id: 4, label: "Приглашение на событие", icon: "🎉", bg: "#fce7f3", questions: [
    { title: "Ваше имя", type: "text", options: [], required: true },
    { title: "Вы приходили раньше?", type: "radio", options: ["Да", "Нет"], required: true },
  ]},
  { id: 5, label: "Заказ футболки", icon: "👕", bg: "#ede9fe", questions: [
    { title: "Ваше имя", type: "text", options: [], required: true },
    { title: "Выберите размер", type: "radio", options: ["XS", "S", "M", "L", "XL", "XXL"], required: true },
  ]},
  { id: 6, label: "Регистрация на событие", icon: "📝", bg: "#fef3c7", questions: [
    { title: "Полное имя", type: "text", options: [], required: true },
    { title: "Email адрес", type: "text", options: [], required: true },
  ]}
];

export default function Home() {
  const navigate = useNavigate();
  const [surveys, setSurveys] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [searchQuery, setSearchQuery] = useState("");

  useEffect(() => {
    loadSurveys();
  }, []);

  const createNewForm = (template = null) => {
    if (template?.questions) {
      localStorage.setItem("templateQuestions", JSON.stringify(template.questions));
      localStorage.setItem("templateTitle", template.label);
    }
    navigate("/editor");
  };

  const logout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    navigate("/login");
  };

  const loadSurveys = async () => {
    try {
      setError("");
      setLoading(true);
      const data = await apiClient.surveys.getAll();
      setSurveys(data.data || []);
    } catch (error) {
      console.error("Error loading surveys:", error);
      setError(`Ошибка: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  const user = JSON.parse(localStorage.getItem("user") || "{}");
  const filteredSurveys = surveys.filter(s => 
    !searchQuery || s.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Roboto:wght@300;400;500;700&display=swap');
        
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { font-family: 'Roboto', sans-serif; background: #f8f9fa; }
        
        /* NAVBAR */
        .navbar {
          background: #fff;
          border-bottom: 1px solid #dadce0;
          padding: 16px 32px;
          display: flex;
          align-items: center;
          gap: 32px;
          position: sticky;
          top: 0;
          z-index: 100;
          box-shadow: 0 1px 2px rgba(60,64,67,0.3);
        }
        
        .navbar-logo {
          display: flex;
          align-items: center;
          gap: 12px;
          cursor: pointer;
          text-decoration: none;
          color: #1f1f1f;
        }
        
        .navbar-logo img {
          width: 40px;
          height: 40px;
        }
        
        .navbar-logo-text {
          font-size: 22px;
          font-weight: 500;
          color: #1f1f1f;
        }
        
        .navbar-search {
          flex: 1;
          max-width: 500px;
        }
        
        .search-input {
          width: 100%;
          padding: 10px 16px;
          border: 1px solid #dadce0;
          border-radius: 24px;
          background: #f8f9fa;
          font-size: 14px;
          font-family: 'Roboto', sans-serif;
          color: #202124;
          transition: all 0.2s;
        }
        
        .search-input:focus {
          outline: none;
          background: #fff;
          border-color: #dadce0;
          box-shadow: 0 1px 4px rgba(32,33,36,0.1);
        }
        
        .search-input::placeholder {
          color: #9aa0a6;
        }
        
        .navbar-actions {
          display: flex;
          align-items: center;
          gap: 12px;
          margin-left: auto;
        }
        
        .logout-btn {
          background: none;
          border: none;
          color: #5f6368;
          cursor: pointer;
          font-size: 14px;
          padding: 8px 12px;
          border-radius: 4px;
          transition: all 0.2s;
          font-family: 'Roboto', sans-serif;
        }
        
        .logout-btn:hover {
          background: #f8f9fa;
          color: #1f1f1f;
        }
        
        /* MAIN CONTENT */
        .main-container {
          max-width: 1400px;
          margin: 0 auto;
          padding: 40px 32px;
        }
        
        /* CREATE SECTION */
        .create-section {
          margin-bottom: 60px;
        }
        
        .create-title {
          font-size: 16px;
          font-weight: 500;
          color: #1f1f1f;
          margin-bottom: 24px;
        }
        
        .templates-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
          gap: 24px;
        }
        
        .template-card {
          background: #fff;
          border: 1px solid #dadce0;
          border-radius: 8px;
          padding: 32px 16px;
          text-align: center;
          cursor: pointer;
          transition: all 0.2s;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          height: 200px;
          text-decoration: none;
          color: inherit;
          box-shadow: 0 1px 3px rgba(60,64,67,0.1);
        }
        
        .template-card:hover {
          box-shadow: 0 4px 16px rgba(60,64,67,0.2);
          transform: translateY(-2px);
          border-color: #dadce0;
        }
        
        .template-icon {
          font-size: 64px;
          margin-bottom: 16px;
          display: block;
        }
        
        .template-label {
          font-size: 13px;
          font-weight: 500;
          color: #202124;
          line-height: 1.4;
        }
        
        /* RECENT SECTION */
        .recent-section {
          margin-top: 60px;
        }
        
        .recent-title {
          font-size: 16px;
          font-weight: 500;
          color: #1f1f1f;
          margin-bottom: 24px;
        }
        
        .recent-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
          gap: 16px;
        }
        
        .survey-card {
          background: #fff;
          border: 1px solid #dadce0;
          border-radius: 8px;
          padding: 16px;
          cursor: pointer;
          transition: all 0.2s;
          box-shadow: 0 1px 3px rgba(60,64,67,0.1);
          text-decoration: none;
          color: inherit;
          display: flex;
          flex-direction: column;
          gap: 12px;
        }
        
        .survey-card:hover {
          box-shadow: 0 4px 16px rgba(60,64,67,0.2);
          transform: translateY(-2px);
        }
        
        .survey-title {
          font-size: 15px;
          font-weight: 500;
          color: #202124;
          word-break: break-word;
        }
        
        .survey-meta {
          display: flex;
          justify-content: space-between;
          font-size: 12px;
          color: #5f6368;
        }
        
        .survey-actions {
          display: flex;
          gap: 8px;
          padding-top: 8px;
          border-top: 1px solid #dadce0;
        }
        
        .survey-action-btn {
          flex: 1;
          padding: 8px;
          border: 1px solid #dadce0;
          background: #fff;
          border-radius: 4px;
          cursor: pointer;
          font-size: 12px;
          color: #1f1f1f;
          font-weight: 500;
          transition: all 0.2s;
          font-family: 'Roboto', sans-serif;
        }
        
        .survey-action-btn:hover {
          background: #f8f9fa;
          border-color: #dadce0;
        }
        
        .empty-state {
          text-align: center;
          padding: 40px;
          color: #5f6368;
        }
        
        .empty-icon {
          font-size: 48px;
          margin-bottom: 16px;
        }
        
        .error-message {
          background: #f8d7da;
          color: #721c24;
          padding: 12px 16px;
          border-radius: 4px;
          margin-bottom: 20px;
          border: 1px solid #f5c6cb;
        }
        
        .loading {
          text-align: center;
          padding: 40px;
          color: #5f6368;
        }
        
        /* Mobile */
        @media (max-width: 768px) {
          .navbar {
            gap: 16px;
            padding: 12px 16px;
            flex-wrap: wrap;
          }
          
          .navbar-logo img {
            width: 36px;
            height: 36px;
          }
          
          .navbar-logo-text {
            font-size: 18px;
          }
          
          .navbar-search {
            flex: 0 0 100%;
            order: 3;
            max-width: 100%;
          }
          
          .navbar-actions {
            margin-left: 0;
          }
          
          .main-container {
            padding: 20px 12px;
          }
          
          .templates-grid {
            grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
            gap: 12px;
          }
          
          .template-card {
            height: 160px;
            padding: 16px 8px;
          }
          
          .template-icon {
            font-size: 40px;
            margin-bottom: 8px;
          }
          
          .template-label {
            font-size: 11px;
          }
          
          .recent-grid {
            grid-template-columns: 1fr;
          }
        }
      `}</style>
      
      {/* NAVBAR */}
      <nav className="navbar">
        <div className="navbar-logo">
          <img src="/fromo.png" alt="Formo" />
          <span className="navbar-logo-text">Formo</span>
        </div>
        
        <div className="navbar-search">
          <input
            type="text"
            placeholder="Поиск форм..."
            className="search-input"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>
        
        <div className="navbar-actions">
          <div style={{ fontSize: '13px', color: '#5f6368', minWidth: '80px', textAlign: 'right' }}>
            {user?.firstName && `${user.firstName} ${user.lastName || ''}`}
          </div>
          <button className="logout-btn" onClick={logout}>Выйти</button>
        </div>
      </nav>
      
      {/* MAIN CONTENT */}
      <div className="main-container">
        {error && <div className="error-message">{error}</div>}
        
        {/* CREATE SECTION */}
        <section className="create-section">
          <h2 className="create-title">Создать форму</h2>
          <div className="templates-grid">
            {TEMPLATES.map(template => (
              <button
                key={template.id}
                className="template-card"
                onClick={() => createNewForm(template)}
                style={{ backgroundColor: template.bg }}
              >
                <span className="template-icon">{template.icon}</span>
                <span className="template-label">{template.label}</span>
              </button>
            ))}
          </div>
        </section>
        
        {/* RECENT SECTION */}
        {(surveys.length > 0 || searchQuery) && (
          <section className="recent-section">
            <h2 className="recent-title">
              {searchQuery ? 'Результаты поиска' : 'Недавние формы'}
            </h2>
            
            {loading ? (
              <div className="loading">Загрузка...</div>
            ) : filteredSurveys.length > 0 ? (
              <div className="recent-grid">
                {filteredSurveys.map(survey => (
                  <div
                    key={survey._id}
                    className="survey-card"
                    onClick={() => navigate(`/answers/${survey._id}`)}
                  >
                    <div className="survey-title">{survey.title}</div>
                    <div className="survey-meta">
                      <span>{survey.questions?.length || 0} вопросов</span>
                      <span>
                        {new Date(survey.createdAt).toLocaleDateString('ru-RU')}
                      </span>
                    </div>
                    <div className="survey-actions">
                      <button
                        className="survey-action-btn"
                        onClick={(e) => {
                          e.stopPropagation();
                          navigate(`/editor/${survey._id}`);
                        }}
                      >
                        Редактировать
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="empty-state">
                <div className="empty-icon">📭</div>
                <p>Формы не найдены</p>
              </div>
            )}
          </section>
        )}
      </div>
    </>
  );
}
